import Button from '@mui/material/Button';
import Checkbox from '@mui/material/Checkbox';
import React, { useState } from 'react'
import DeleteIcon from '@mui/icons-material/Delete';
import EditIcon from '@mui/icons-material/Edit';
import UpdateTaskForm from './UpdateTaskForm';
import classnames from 'classnames';
import Typography from '@mui/material/Typography';

const Task = ({ task }) => {
  const {id, name, completed} = task;
  const [isComplete, setIsComplete] = useState(completed);
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const handleUpdateTaskComplete = () => {
    setIsComplete((prev) => !prev);
  };
  const handleDeleteTask = () => {
    console.log("delete task")
  };
  return (
    <div className="task">
        <div className={classnames("flex", { done: isComplete })}>
            <Checkbox checked={isComplete} onChange={handleUpdateTaskComplete} />
            <Typography variant="h4">{name}</Typography>
        </div>
        <div classname="taskButtons">
            <Button variant="contained" onClick={() => setIsDialogOpen(true)} color="primary">
                <EditIcon />
            </Button>
            <Button variant="contained" onClick={handleDeleteTask} color="error">
                <DeleteIcon />
            </Button>
        </div>
        <UpdateTaskForm isDialogOpen={isDialogOpen} setIsDialogOpen={setIsDialogOpen} task={task} />
    </div>
  )
}

export default Task
